"use client";

import { useTrades } from "@/hooks/useTrades";
import React, { useState } from "react";
import TradeModal from "./TradeModal";

export default function TradeList({ userId }: { userId: string }) {
  const { data: trades, isLoading, isError } = useTrades(userId);
  const [isModalOpen, setIsModalOpen] = useState(false);

  const now = new Date();
  const today = new Date();

  if (isLoading) return <div className="text-white">Loading trades...</div>;
  if (isError) return <div className="text-red-500">Error loading trades</div>;

  if (!trades || trades.length === 0)
    return <div className="text-gray-400">No trades found.</div>;

  return (
    <>
      <div className="text-white p-6 space-y-4 w-[100%]">
        <h2 className="font-semibold">Trades:</h2>
        <ul className="bg-[#16151C] border border-white/10 rounded-lg pl-4">
          {trades.slice(0, 3).map((trade) => (
            <li
              key={trade._id}
              className="p-3 pl-0 border-b border-white/10 last:border-0"
            >
              <div className="flex justify-between items-center">
                <div>
                  <div className="uppercase text-sm">
                    {trade.symbol} <span className="lowercase">x</span>{" "}
                    {trade.qty}
                  </div>
                </div>
                <div
                  className={`text-sm ${
                    trade.status === "OPEN" ? "text-green-600" : "text-red-600"
                  }`}
                >
                  {trade.status === "OPEN" ? trade.status : "CLOSED"}
                </div>
              </div>
            </li>
          ))}
          <li className="p-2 pr-3 flex justify-end">
            <div
              className="bg-white/10 w-6 text-center rounded-full cursor-pointer"
              onClick={() => setIsModalOpen(true)}
            >
              +
            </div>
          </li>
        </ul>
        <div className="flex justify-end">
          <button className="bg-blue-800 py-2 px-4 rounded-md">See all</button>
        </div>
      </div>
      {isModalOpen && (
        <TradeModal
          date={today}
          onClose={() => setIsModalOpen(false)}
          onSave={(newTrade) => {
            // Call backend to save trade
            fetch("/api/trades", {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify({ ...newTrade, userId }),
            })
              .then((res) => res.json())
              .then(() => {
                // Re-fetch trades so the new one shows
                // If using react-query or SWR, just call mutate()
              });

            setIsModalOpen(false);
          }}
        />
      )}
    </>
  );
}
